    /// Create from NATS client.
    pub fn new(client: NatsClient) -> Self {
        Self { client }
    }

    /// Create or update a stream.
    pub async fn create_stream(
        &self,
        cx: &Cx,
        config: StreamConfig,
    ) -> Outcome<Stream, JsError> {
        // Send request to $JS.API.STREAM.CREATE.<stream>
    }

    /// Get existing stream.
    pub async fn get_stream(
        &self,
        cx: &Cx,
        name: &str,
    ) -> Outcome<Stream, JsError>;

    /// Delete stream.
    pub async fn delete_stream(
        &self,
        cx: &Cx,
        name: &str,
    ) -> Outcome<(), JsError>;
}
```

### Publishing to Streams
```rust
